import json
from collections import defaultdict
import os

# Load data using the locals() function for storage variables
childrens_books_var = locals().get('var_functions.query_db:42')
reviews_var = locals().get('var_functions.query_db:24')

# Process children's books data
if isinstance(childrens_books_var, str):
    if os.path.isfile(childrens_books_var):
        with open(childrens_books_var, 'r') as f:
            childrens_books = json.load(f)
    else:
        childrens_books = []
else:
    childrens_books = childrens_books_var

# Process reviews data  
if isinstance(reviews_var, str):
    if os.path.isfile(reviews_var):
        with open(reviews_var, 'r') as f:
            reviews = json.load(f)
    else:
        reviews = []
else:
    reviews = reviews_var

# Create lookup dictionary for children's books by book_id
childrens_lookup = {}
for book in childrens_books:
    childrens_lookup[book['book_id']] = book['title']

# Group ratings by book_id
review_ratings = defaultdict(list)
for review in reviews:
    purchase_id = review['purchase_id']
    # Convert purchase_id (purchaseid_X) to book_id (bookid_X) format
    book_id = purchase_id.replace('purchaseid_', 'bookid_', 1)
    if book_id in childrens_lookup:
        rating = float(review['rating'])
        review_ratings[book_id].append(rating)

# Calculate average ratings and filter for books with >= 4.5 average rating
qualified_books = []
for book_id, ratings in review_ratings.items():
    if ratings:  # Ensure there are reviews
        avg_rating = sum(ratings) / len(ratings)
        if avg_rating >= 4.5:
            qualified_books.append({
                'title': childrens_lookup[book_id],
                'average_rating': round(avg_rating, 2),
                'num_reviews': len(ratings)
            })

# Sort by average rating descending
qualified_books.sort(key=lambda x: x['average_rating'], reverse=True)

print('__RESULT__:')
print(json.dumps(qualified_books))

